import random
import time

class Hacker:
    def __init__(self, password):
        self.password = password

    def try_password(self, guess):
        if guess == self.password:
            print("Access granted! The password was " + self.password)
        else:
            print("Access denied. Try again.")

    def hack(self):
        for attempt in range(1, 6):
            guess = input("Enter your password guess: ")
            self.try_password(guess)
            if guess == self.password:
                break
            else:
                print("You have " + str(5 - attempt) + " attempts left.")
        else:
            print("You have used all your attempts. The password was " + self.password)

if __name__ == "__main__":
    password = "dragonball"
    hacker = Hacker(password)
    hacker.hack()
```

